+/// LRU eviction for `IndexMap<(u64, i64), CacheEntry<T>>`.
+fn lru_evict_if_full_u64_i64<T>(
+    map: &mut IndexMap<(u64, i64), CacheEntry<T>>,
+    ttl: Duration,
+    capacity: usize,
+) {
+    if map.len() < capacity {
+        return;
+    }
+    map.retain(|_, entry| !entry.is_expired(ttl));
+    while map.len() >= capacity {
+        map.shift_remove_index(0);
+    }
+}
